// optional import of sdk modules
import { execution } from '@dynatrace-sdk/automation-utils';
import { workflowsClient } from "@dynatrace-sdk/client-automation";

export default async function ({ execution_id }) {
  // your code goes here
  // e.g. get the current execution
  const ex = await execution(execution_id);
  console.log(ex.workflow)


  const getowner = await workflowsClient.getWorkflows({
    adminAccess: true,
    id: ex.workflow,
  });


  const data = await workflowsClient.getWorkflows({
    limit: 1000,
    owner: getowner.results[0].owner,
  });


  let i = 0;

  while (i < data.results.length) {
      console.log(data.results[i].id);
      const datax = await workflowsClient.deleteWorkflow({
      adminAccess: true,
      id: ""+ data.results[i].id +"",
      });
      console.log(data.results[i].title ) 
      i++;
  }



  return data.results.length;
}
